@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    @Primary
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .oauth2Client(oauth2Client -> oauth2Client
                .defaultOAuth2Client()
            )
            .oauth2Login(oauth2Login -> oauth2Login
                .defaultSuccessUrl("/dashboard", true)
                .failureUrl("/login?error=true")
            )
            .oauth2ResourceServer(oauth2ResourceServer -> oauth2ResourceServer
                .jwt(jwt -> jwt.decoder(jwtDecoder()))
            );
        return http.build();
    }

    @Bean
    public ClientRegistrationRepository clientRegistrationRepository() {
        ClientRegistration registration = ClientRegistration.withRegistrationId("oidc")
            .clientId("your-client-id")
            .clientSecret("your-client-secret")
            .authorizationUri("https://your-oidc-provider.com/oauth/authorize")
            .tokenUri("https://your-oidc-provider.com/oauth/token")
            .userInfoUri("https://your-oidc-provider.com/oauth/userinfo")
            .userNameAttributeName("sub")
            .scope("openid", "profile", "email")
            .redirectUri("{baseUrl}/login/oauth2/code/{registrationId}")
            .clientName("OIDC Provider")
            .build();
        return new InMemoryClientRegistrationRepository(registration);
    }

    @Bean
    public JwtDecoder jwtDecoder() {
        NimbusJwtDecoder jwtDecoder = new NimbusJwtDecoder(jwkSetUri());
        jwtDecoder.setJwtValidator(jwtValidator());
        return jwtDecoder;
    }

    @Bean
    public String jwkSetUri() {
        return "https://your-oidc-provider.com/oauth/keys";
    }

    @Bean
    public JwtValidator jwtValidator() {
        return new JwtValidator() {
            @Override
            public Jwt validate(Jwt jwt) {
                return jwt;
            }
        };
    }
}

@Component
public class OidcAuthenticationService {
    
    private final ClientRegistrationRepository clientRegistrationRepository;
    
    public OidcAuthenticationService(ClientRegistrationRepository clientRegistrationRepository) {
        this.clientRegistrationRepository = clientRegistrationRepository;
    }
    
    public Map<String, Object> getUserInfo(String accessToken) {
        ClientRegistration clientRegistration = clientRegistrationRepository.findByRegistrationId("oidc");
        String userInfoUri = clientRegistration.getProviderDetails().getUserInfoUri();
        
        RestTemplate restTemplate = new RestTemplate();
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        HttpEntity<String> entity = new HttpEntity<>(headers);
        
        ResponseEntity<Map> response = restTemplate.exchange(
            userInfoUri, 
            HttpMethod.GET, 
            entity, 
            Map.class
        );
        
        return response.getBody();
    }
    
    public String extractSubjectFromToken(String idToken) {
        try {
            JwtDecoder jwtDecoder = new NimbusJwtDecoder(jwkSetUri());
            Jwt jwt = jwtDecoder.decode(idToken);
            return jwt.getSubject();
        } catch (Exception e) {
            throw new RuntimeException("Failed to decode JWT token", e);
        }
    }
    
    private String jwkSetUri() {
        return "https://your-oidc-provider.com/oauth/keys";
    }
}

@RestController
public class AuthController {
    
    private final OidcAuthenticationService oidcService;
    
    public AuthController(OidcAuthenticationService oidcService) {
        this.oidcService = oidcService;
    }
    
    @GetMapping("/dashboard")
    public String dashboard(Authentication authentication) {
        if (authentication instanceof OAuth2AuthenticationToken) {
            OAuth2AuthenticationToken oauth2Token = (OAuth2AuthenticationToken) authentication;
            String accessToken = oauth2Token.getAccessToken().getTokenValue();
            Map<String, Object> userInfo = oidcService.getUserInfo(accessToken);
            return "Welcome " + userInfo.get("name");
        }
        return "Welcome Guest";
    }
}